// Sempre emite 1 item. Se houver municipios pendentes, devolve rows[]; senao, devolve { __empty:true }.
// Tambem filtra o placeholder {success:true} que o Postgres v2.6 injeta quando 0 linhas + alwaysOutputData.
const rows = [];
for (const it of $input.all()) {
  const j = it.json || {};
  if (j && j.mun && j.est && j.query_key) rows.push(j);
}
if (!rows.length) {
  return [{ json: { __empty: true } }];
}
return rows.map(j => ({ json: j }));

// Pega o município atual do loop (sempre disponível) e o resultado do Nominatim (pode ser array vazio, undefined, ou erro).
const loopItem = $('Loop One-by-One').item.json || {};
if (!loopItem.mun || !loopItem.est || !loopItem.query_key) {
  // item inválido entrou no loop — não devia, mas defendemos
  return [];
}
const all = $input.all();
const first = all.length ? (all[0].json || {}) : {};
let body = first;
if (Array.isArray(first)) body = first;
else if (first && Array.isArray(first.data)) body = first.data;
let lat = null, lng = null, display = null, okFlag = false;
const hit = Array.isArray(body) && body.length ? body[0] : (body && body.lat != null ? body : null);
if (hit){
  lat = Number(hit.lat); lng = Number(hit.lon);
  display = String(hit.display_name || '');
  okFlag = Number.isFinite(lat) && Number.isFinite(lng);
}
return [{ json: { mun: loopItem.mun, est: loopItem.est, query_key: loopItem.query_key, lat, lng, display, ok: okFlag } }];
